"genres": [
"Documentary"
],
"_federation": {
"indexUid": "comics",
"queriesPosition": 0,
"weightedRankingScore": 0.9848484848484848,
"remote": "ms1"
}
},
{
"title": "Superman: Red Son",
"genres": [],
"_federation": {
"indexUid": "movies",
"queriesPosition": 1,
"weightedRankingScore": 0.9848484848484849,
"remote": "ms0"
}
